import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';
import './AdminDashboard.css';

function AdminDashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab] = useState('products');
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({
    name: '', price: '', description: '', image: '', category: 'Electronics', countInStock: '',
  });

  useEffect(() => {
    if (!user || !user.isAdmin) { navigate('/'); return; }
    loadData();
  }, [user]);

  const loadData = () => {
    api.get('/products').then((res) => setProducts(res.data));
    api.get('/orders').then((res) => setOrders(res.data)).catch(() => {});
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editing) {
        await api.put(`/products/${editing}`, form);
        toast.success('Product updated');
      } else {
        await api.post('/products', form);
        toast.success('Product created');
      }
      setShowForm(false);
      setEditing(null);
      setForm({ name: '', price: '', description: '', image: '', category: 'Electronics', countInStock: '' });
      loadData();
    } catch (err) {
      toast.error('Operation failed');
    }
  };

  const handleEdit = (p) => {
    setEditing(p._id);
    setForm({
      name: p.name, price: p.price, description: p.description,
      image: p.image, category: p.category, countInStock: p.countInStock,
    });
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    await api.delete(`/products/${id}`);
    toast.success('Deleted');
    loadData();
  };

  const markDelivered = async (id) => {
    await api.put(`/orders/${id}/deliver`);
    toast.success('Marked as delivered');
    loadData();
  };

  return (
    <div className="admin-page fade-in">
      <div className="container">
        <h1 className="page-title">Admin Dashboard</h1>

        <div className="admin-stats">
          <div className="stat-card">
            <small>Total Products</small>
            <strong>{products.length}</strong>
          </div>
          <div className="stat-card">
            <small>Total Orders</small>
            <strong>{orders.length}</strong>
          </div>
          <div className="stat-card">
            <small>Revenue</small>
            <strong>${orders.reduce((s, o) => s + o.totalPrice, 0).toFixed(2)}</strong>
          </div>
        </div>

        <div className="admin-tabs">
          <button className={tab === 'products' ? 'active' : ''} onClick={() => setTab('products')}>Products</button>
          <button className={tab === 'orders' ? 'active' : ''} onClick={() => setTab('orders')}>Orders</button>
        </div>

        {tab === 'products' && (
          <>
            <button className="btn btn-primary" onClick={() => { setShowForm(!showForm); setEditing(null); }}>
              {showForm ? 'Cancel' : '+ Add Product'}
            </button>

            {showForm && (
              <form onSubmit={handleSubmit} className="admin-form">
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Name</label>
                    <input className="form-input" required value={form.name}
                      onChange={(e) => setForm({...form, name: e.target.value})} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Price</label>
                    <input type="number" step="0.01" className="form-input" required value={form.price}
                      onChange={(e) => setForm({...form, price: e.target.value})} />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Category</label>
                    <select className="form-select" value={form.category}
                      onChange={(e) => setForm({...form, category: e.target.value})}>
                      <option>Electronics</option><option>Fashion</option>
                      <option>Home</option><option>Books</option><option>Sports</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Stock</label>
                    <input type="number" className="form-input" required value={form.countInStock}
                      onChange={(e) => setForm({...form, countInStock: e.target.value})} />
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">Image URL</label>
                  <input className="form-input" value={form.image}
                    onChange={(e) => setForm({...form, image: e.target.value})} />
                </div>
                <div className="form-group">
                  <label className="form-label">Description</label>
                  <textarea className="form-textarea" rows="4" required value={form.description}
                    onChange={(e) => setForm({...form, description: e.target.value})} />
                </div>
                <button type="submit" className="btn btn-primary btn-lg">
                  {editing ? 'Update' : 'Create'} Product
                </button>
              </form>
            )}

            <div className="admin-table">
              <table>
                <thead>
                  <tr><th>Image</th><th>Name</th><th>Category</th><th>Price</th><th>Stock</th><th></th></tr>
                </thead>
                <tbody>
                  {products.map((p) => (
                    <tr key={p._id}>
                      <td><img src={p.image} alt={p.name} className="table-img" /></td>
                      <td><strong>{p.name}</strong></td>
                      <td>{p.category}</td>
                      <td>${p.price.toFixed(2)}</td>
                      <td>{p.countInStock}</td>
                      <td>
                        <button className="btn-icon" onClick={() => handleEdit(p)}>Edit</button>
                        <button className="btn-icon danger" onClick={() => handleDelete(p._id)}>Delete</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        )}

        {tab === 'orders' && (
          <div className="admin-table">
            <table>
              <thead>
                <tr><th>Order ID</th><th>Customer</th><th>Date</th><th>Total</th><th>Status</th><th></th></tr>
              </thead>
              <tbody>
                {orders.map((o) => (
                  <tr key={o._id}>
                    <td>#{o._id.slice(-6).toUpperCase()}</td>
                    <td>{o.user?.name || 'N/A'}</td>
                    <td>{new Date(o.createdAt).toLocaleDateString()}</td>
                    <td>${o.totalPrice.toFixed(2)}</td>
                    <td>
                      <span className={`status-badge ${o.isDelivered ? 'delivered' : 'pending'}`}>
                        {o.isDelivered ? 'Delivered' : 'Pending'}
                      </span>
                    </td>
                    <td>
                      {!o.isDelivered && (
                        <button className="btn-icon" onClick={() => markDelivered(o._id)}>Mark Delivered</button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

export default AdminDashboard;
